import time
from enum import Enum
from dataclasses import dataclass, field
from typing import Callable, Any

class CircuitState(Enum):
    CLOSED = "closed"       # Normal operation
    OPEN = "open"           # Failing — reject immediately
    HALF_OPEN = "half_open" # Probing — allow one request through

@dataclass
class CircuitBreaker:
    failure_threshold: int = 5       # failures before opening
    recovery_timeout: float = 30.0   # seconds before half-open probe
    _failures: int = field(default=0, init=False)
    _state: CircuitState = field(default=CircuitState.CLOSED, init=False)
    _opened_at: float = field(default=0.0, init=False)

    def call(self, fn: Callable, *args, **kwargs) -> Any:
        if self._state == CircuitState.OPEN:
            if time.monotonic() - self._opened_at > self.recovery_timeout:
                self._state = CircuitState.HALF_OPEN
            else:
                raise RuntimeError("Circuit open — model endpoint unavailable")

        try:
            result = fn(*args, **kwargs)
            self._on_success()
            return result
        except Exception as exc:
            self._on_failure()
            raise

    def _on_success(self):
        self._failures = 0
        self._state = CircuitState.CLOSED

    def _on_failure(self):
        self._failures += 1
        if self._failures >= self.failure_threshold or self._state == CircuitState.HALF_OPEN:
            self._state = CircuitState.OPEN
            self._opened_at = time.monotonic()

# Usage
opus_breaker = CircuitBreaker(failure_threshold=3, recovery_timeout=60)
sonnet_breaker = CircuitBreaker(failure_threshold=5, recovery_timeout=30)

import anthropic
from dataclasses import dataclass
from typing import Optional

client = anthropic.Anthropic()

ROUTING_POLICY = {
    "reasoning":       ("claude-opus-4-8", 8192),
    "complex-analysis": ("claude-opus-4-8", 8192),
    "summarization":   ("claude-sonnet-5", 4096),
    "drafting":        ("claude-sonnet-5", 4096),
    "classification":  ("claude-haiku-4-5-20251001", 1024),
    "intent-detection": ("claude-haiku-4-5-20251001", 512),
}
FALLBACK_CHAIN = {
    "claude-opus-4-8":          "claude-sonnet-5",
    "claude-sonnet-5":          "claude-haiku-4-5-20251001",
    "claude-haiku-4-5-20251001": None,  # no further fallback
}

@dataclass
class RoutedResponse:
    content: str
    model_used: str
    degraded: bool
    fallback_reason: Optional[str]

def route_request(task_type: str, messages: list, system: str = "") -> RoutedResponse:
    model, max_tokens = ROUTING_POLICY.get(task_type, ("claude-sonnet-5", 4096))
    tried = []

    while model is not None:
        try:
            kwargs = {"model": model, "max_tokens": max_tokens, "messages": messages}
            if system:
                kwargs["system"] = system
            response = client.messages.create(**kwargs)
            return RoutedResponse(
                content=response.content[0].text,
                model_used=model,
                degraded=bool(tried),
                fallback_reason=f"primary {'→'.join(tried)} unavailable" if tried else None,
            )
        except Exception as exc:
            tried.append(model)
            model = FALLBACK_CHAIN.get(model)

    return RoutedResponse(
        content="Service temporarily unavailable. Please retry in a few minutes.",
        model_used="none",
        degraded=True,
        fallback_reason=f"all models exhausted: {tried}",
    )

# Example usage
result = route_request(
    task_type="summarization",
    messages=[{"role": "user", "content": "Summarize this 10-page legal agreement..."}],
    system="You are a precise legal summarization assistant.",
)
print(f"Model: {result.model_used}, Degraded: {result.degraded}")
